	for _, b := range allBeads {
		if b.IssueType == IssueTypeReviewFinding {
			reviewFindingCount++
		}
	}
	if reviewFindingCount != 2 {
		t.Errorf("expected 2 review-finding beads after different payload, got %d", reviewFindingCount)
	}
}

